export type Cell = [number, number];

const encodeCell = ([x, y]: Cell): string => `${x},${y}`;
const decodeCell = (key: string): Cell => {
  const [x, y] = key.split(",").map(Number);
  return [x, y];
};

const neighborsOf = ([x, y]: Cell): Cell[] => {
  const neighbors: Cell[] = [];
  for (let dx = -1; dx <= 1; dx++) {
    for (let dy = -1; dy <= 1; dy++) {
      if (dx === 0 && dy === 0) continue;
      neighbors.push([x + dx, y + dy]);
    }
  }
  return neighbors;
};

export function nextGeneration(liveCells: Cell[]): Cell[] {
  const liveSet = new Set(liveCells.map(encodeCell));
  const candidates = new Set<string>();
  for (const cell of liveCells) {
    candidates.add(encodeCell(cell));
    for (const neighbor of neighborsOf(cell)) {
      candidates.add(encodeCell(neighbor));
    }
  }
  const result: Cell[] = [];
  for (const key of candidates) {
    const cell = decodeCell(key);
    const liveNeighborCount = neighborsOf(cell).filter((n) =>
      liveSet.has(encodeCell(n))
    ).length;
    const isAlive = liveSet.has(key);
    if (isAlive && (liveNeighborCount === 2 || liveNeighborCount === 3)) {
      result.push(cell);
    } else if (!isAlive && liveNeighborCount === 3) {
      result.push(cell);
    }
  }
  return result;
}
